#include<bits/stdc++.h>
#define int long long
using namespace std;
const int N=550,mod=1e9+7;
int dp[N][N][5];
int n,k;
char S[N];
signed main(){
	scanf("%d%d",&n,&k);
	scanf("%s",S + 1);
	for(int i = 1; i <= n; i++)  dp[i][i - 1][0] = 1; 
	for(int len = 1;len <= n;len++) 
		for(int i = 1,j = i + len - 1; j <= n;i++,j++) { 
			if(len <= k and dp[i][j-1][0] and (S[j]=='*'||S[j]=='?')) dp[i][j][0]=1;
			if(len>=2)	{
				if((S[i] == '(' or S[i]=='?') and (S[j]==')' or S[j]=='?'))
					dp[i][j][1]=(dp[i+1][j-1][0]+dp[i+1][j-1][2]+dp[i+1][j-1][3]+dp[i+1][j-1][4])%mod;
				for(int t=i;t<=j-1;++t)	{
					dp[i][j][2] = (dp[i][j][2]+dp[i][t][3]*dp[t+1][j][0])%mod;
					dp[i][j][3]=(dp[i][j][3]+(dp[i][t][2]+dp[i][t][3])*dp[t+1][j][1])%mod;
					dp[i][j][4]=(dp[i][j][4]+dp[i][t][0]*dp[t+1][j][3])%mod;
				}
			}
            dp[i][j][3]=(dp[i][j][3]+dp[i][j][1])%mod;
		}
	printf("%lld",dp[1][n][3]);
}
